// ARCHIVO: supabase/functions/server/db.ts (ACTUAL EN MAIN)
// Contiene: authenticate(), extractToken(), getAdminClient(), getUserClient(), err(), ok()

// ENV VALIDATION — throw en top-level (crashea isolate):
const SUPABASE_URL = Deno.env.get('SUPABASE_URL');
const SUPABASE_ANON_KEY = Deno.env.get('SUPABASE_ANON_KEY');
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
if (!SUPABASE_URL || !SUPABASE_ANON_KEY || !SUPABASE_SERVICE_ROLE_KEY) {
  throw new Error(`[Axon Fatal] Missing required env vars: ${missing}`);
}

// AUTHENTICATE — VULNERABILIDAD H1:
// Comment literal en el código: 'Does NOT verify the cryptographic signature (PostgREST/RLS handles that)'
// WARNING: 'If a route calls an external API (OpenAI, Stripe) using user.id WITHOUT making any Supabase DB query,
//          the JWT is NEVER cryptographically validated. An attacker could forge a JWT and consume paid API credits.'
const decodeJwtPayload = (token: string) => {
  // Base64URL decode sin verificar firma
  const parts = token.split('.');
  if (parts.length !== 3) return null;
  let base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
  const pad = base64.length % 4;
  if (pad === 1) return null;
  if (pad) base64 += '='.repeat(4 - pad);
  const json = atob(base64);
  return JSON.parse(json);
};

export const authenticate = async (c: Context) => {
  const token = extractToken(c);
  if (!token) return err(c, 'Missing Authorization header', 401);
  const payload = decodeJwtPayload(token);
  if (!payload) return err(c, 'Malformed or invalid JWT', 401);
  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) return err(c, 'JWT has expired', 401);
  const db = getUserClient(token);
  return { user: { id: payload.sub, email: payload.email ?? '' }, db };
};

// NOTAS:
// - decodeJwtPayload es `const` (NO export) — safe delete en D2
// - authenticate() ya es async — compatible con jose.jwtVerify
// - err() hace console.error + c.json({error}, status)

// ARCHIVO: supabase/functions/server/routes/ai/index.ts
// VULNERABILIDAD H2: Rate limiter DOBLEMENTE fail-open

async function aiRateLimitMiddleware(c: Context, next: Next) {
  if (c.req.method !== 'POST') return next();
  const url = new URL(c.req.url);
  if (url.pathname.endsWith('/ai/report')) return next();      // P6: no Gemini cost
  if (url.pathname.endsWith('/ai/pre-generate')) return next(); // D9: own bucket
  try {
    const auth = await authenticate(c);
    if (auth instanceof Response) return auth;
    const userId = auth.user.id;
    const adminDb = getAdminClient();
    const { data, error } = await adminDb.rpc('check_rate_limit', {
      p_key: `ai:${userId}`, p_max_requests: 20, p_window_ms: 3600000
    });
    if (error) {
      console.warn(`[AI RateLimit] RPC failed. Allowing request.`); // FAIL-OPEN #1
      return next();
    }
    if (data && !data.allowed) {
      return err(c, 'AI rate limit exceeded...', 429);
    }
  } catch (e) {
    console.warn(`[AI RateLimit] Exception. Allowing request.`); // FAIL-OPEN #2
  }
  return next(); // DEFAULT: permite todo
}

// FIX D1: cambiar ambos `return next()` por `return c.json({error:'rate_limit_unavailable'}, 503)`
// 11 sub-módulos: generate, generate-smart, report, report-dashboard, pre-generate, ingest, re-chunk, chat, feedback, analytics, ingest-pdf

// ARCHIVO: supabase/functions/server/rate-limit.ts
// HALLAZGO H6: extractKey() duplica la lógica de atob() de decodeJwtPayload
// Config: 120 req/min/user, 60s window, in-memory Map per-isolate

export function extractKey(token: string): string {
  try {
    const parts = token.split('.');
    if (parts.length === 3) {
      let base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
      const pad = base64.length % 4;
      if (pad === 1) throw new Error('invalid base64');
      if (pad) base64 += '='.repeat(4 - pad);
      const payload = JSON.parse(atob(base64)); // atob() SIN verificar firma
      if (typeof payload.sub === 'string' && payload.sub.length > 0) {
        return `uid:${payload.sub}`;
      }
    }
  } catch { /* fall through */ }
  const lastDot = token.lastIndexOf('.');
  if (lastDot !== -1) return `sig:${token.substring(lastDot + 1, lastDot + 33)}`;
  return `raw:${token.substring(Math.max(0, token.length - 32))}`;
}

// RIESGO: JWTs falsos con sub rotados crean buckets nuevos (bypass rate limit)
// MITIGACIÓN: authenticate() rechaza DESPUÉS del rate limiter
// DECISIÓN debate-002: Es P2 tech debt, NO se toca en D1-D4

export async function rateLimitMiddleware(c: Context, next: Next) {
  if (path.endsWith('/health') || path.includes('/webhooks/')) return next();
  const token = extractToken(c);
  if (!token) return next(); // no token = no rate limit
  const key = extractKey(token);
  const result = checkRateLimitLocal(key, now);
  if (!result.allowed) return c.json({error: 'Rate limit exceeded', retry_after_seconds}, 429);
  return next();
}

