```typescript
// agentStore.ts - Zustand
interface AgentState {
  // Diccionario O(1)
  statuses: Record<string, 'idle' | 'thinking' | 'speaking' | 'blocked'>;
  updateStatus: (agentId: string, status: string) => void;
