### ARCHIVO 1: hooks/useDebateState.ts (el corazón)

```typescript
import { useState, useEffect, useRef, useCallback } from 'react';

interface DebateState {
  messages: Message[];
  agents: Agent[];
  phase: string;
  round: number;
  totalRounds: number;
  title: string;
}

export const useDebateState = (debateId: string) => {
  const [state, setState] = useState<DebateState | null>(null);
  const lastMsgCount = useRef(0);
  const isVisible = usePageVisibility();

  const poll = useCallback(async () => {
    if (!isVisible) return; // No poll en background

    // 1. Lightweight status check
    const status = await fetchEstado(debateId);
    const newCount = status.messageCount;

    // 2. Delta load solo si hay nuevos
    if (newCount > lastMsgCount.current) {
      const newMsgs = await fetchLeer(debateId, lastMsgCount.current);
      setState(prev => ({
        ...prev!,
        messages: [...(prev?.messages || []), ...newMsgs],
        ...status,
      }));
      lastMsgCount.current = newCount;
    } else {
      // Solo actualiza metadata (fase, ronda, agentes)
      setState(prev => prev ? { ...prev, ...status } : null);
    }
  }, [debateId, isVisible]);

  useEffect(() => {
    poll(); // Initial load
    const id = setInterval(poll, isVisible ? 5000 : 30000);
    return () => clearInterval(id);
  }, [poll, isVisible]);

  return state;
};
```

Esto es el hook que propuse, CON las optimizaciones del **agente-guardian-escalabilidad** (delta-loading + visibilityState). ~40 líneas funcionales. Consume directamente las herramientas MCP de SUPERNOVA: `estado` para metadata y `leer` con `desde_mensaje` para delta.

